export class CompanyPage extends BaseSearchComponent implements OnInit {
  @ViewChild('companyNewEditModal') companyNewEditModal!: CompanyNewEditModalComponent;
  public form!: TypedFormGroup<FilterForm>;
  public title = 'Compañías';
  public companies: GetCompanyModel[] = [];
  #formBuilder = inject(FormBuilder);
  #service = inject(CompanyService);

  constructor(@Inject(ViewContainerRef) viewContainerRef: ViewContainerRef) {
    super(MODULES.COMPANY, viewContainerRef);
  }

  ngOnInit(): void {
    this.createForm();
    this.onSearch();
  }

  createForm() {
    this.form = this.#formBuilder.group(buildFilterForm());
  }

  onSearch(filter: any = null, page = 1) {
    const sort = filterSort(this.form.value);
    const filterToUse = filter || mapParams(this.form.value);
    const pageSize = 10;
    const pageParams = new PageParamsModel(page, pageSize);
    this.updateFilter(filterToUse);
    this.updateSort(sort);
    this.updatePage(pageParams);
    const params = this.getPageParams();
    const subscription = this.#service.search(params).subscribe({
      next: (response) => {
        if (response.isValid) {
          this.total = response.data.total;
          this.companies = response.data.items as any;
        } else {
          console.error(response);
        }
      },
      error: (response) => {
        console.error(response?.messages ?? response);
      },
    });
    this.subscriptions.push(subscription);
  }

  onPageChange(page: number): void {
    this.onSearch(this.filter, page);
  }

  onClean() {
    this.form.reset();
  }

  openModal(id?: number) {
    if (this.companyNewEditModal) {
      this.companyNewEditModal.openModal(id, () => {
        this.onSearch();
      });
    }
  }
}

